    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Easy',
    4,
    'Obese Beginner Safe Start - 4w 2x/wk',
    'body_specific',
    2,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Obese Beginner Safe Start'
ON CONFLICT DO NOTHING;

